import NavBar from "./components/NavBar";
import { useMediaQuery } from "react-responsive";
import SearchBar from "./components/SearchBar";
import { useState, useEffect } from "react";
import { Switch, Route, HashRouter } from "react-router-dom";
import requests from "./requests";
import Row from "./components/Row";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import AllAbout from "./components/AllAbout";
import { Redirect } from "react-router";
import ALLMovies from "./components/ALLMovies";
import WatchList from "./components/WatchList";
import SearchPage from "./components/SearchPage";
import Loading from "./components/Loading";
import { Helmet } from "react-helmet";

function App() {
  const isSmallScreen = useMediaQuery({ query: "(max-width: 563px)" });
  const [allAboutMovie, setAllAboutMovie] = useState({});
  const [movies, setMovies] = useState([]);
  const [showSearchMenu, setShowSearchMenu] = useState(false);

  const [watchListLen, setWatchListLen] = useState(0);
  const [watchList, SetWatchList] = useState([]);
  // here i want to gett watchlist onload
  useEffect(() => {
    document.title = "Moviea";
    const list = JSON.parse(localStorage.getItem("watchlist"));
    if (list === null) {
      localStorage.setItem("watchlist", JSON.stringify([]));
      return;
    } else {
      SetWatchList(list);
    }
  }, []);

  useEffect(() => {
    setWatchListLen(watchList.length);
  }, [watchList]);

  const [isLoading, setIsLoading] = useState(false);
  return (
    <div className="App">
      <Helmet>
        <title>Moviea</title>
        <meta
          name="description"
          content="Do you Want To Search For A Movie ? Bored And you Need  A Movie To Watch ? You Have Moviea "
        ></meta>

        <meta property="og:type" content="website"></meta>
        <meta property="og:url" content="https://moviea.netlify.app/"></meta>
        <meta property="og:title" content="Make Your Movies Watch List"></meta>
        <meta
          property="og:description"
          content="Do you Want To Search For A Movie ? Bored And you Need  A Movie To Watch ?
        You Have Moviea "
        ></meta>
        <meta
          property="og:image"
          content="https://wallpaperaccess.com/full/752715.jpg"
        ></meta>

        <meta property="twitter:card" content="summary_large_image"></meta>
        <meta
          property="twitter:url"
          content="https://moviea.netlify.app/"
        ></meta>
        <meta
          property="twitter:title"
          content="Make Your Movies Watch List"
        ></meta>
        <meta
          property="twitter:description"
          content="Do you Want To Search For A Movie ? Bored And you Need  A Movie To Watch ?
        You Have Moviea "
        ></meta>
        <meta
          property="twitter:image"
          content="https://wallpaperaccess.com/full/752715.jpg"
        ></meta>
        <meta name="theme-color" content="#0d354f"></meta>
      </Helmet>
      {isLoading && <Loading />}
      <HashRouter>
        <NavBar
          movies={movies}
          setMovies={setMovies}
          showSearchMenu={showSearchMenu}
          setShowSearchMenu={setShowSearchMenu}
          watchListLen={watchListLen}
        />
        {isSmallScreen && (
          <div className="SearchBarHolderWhenOnMobile">
            <SearchBar
              Class="SearchBar SearchBarOnMobile"
              movies={movies}
              setMovies={setMovies}
              showSearchMenu={showSearchMenu}
              setShowSearchMenu={setShowSearchMenu}
            />
          </div>
        )}
        <Switch>
          <Route path="/search-page">
            <SearchPage movies={movies} />
          </Route>
          <Route path="/all-movies">
            <ALLMovies />
          </Route>
          <Route path="/all-about/:type/:id">
            {allAboutMovie ? (
              <AllAbout
                movie={allAboutMovie}
                watchList={watchList}
                setWatchList={SetWatchList}
                watchListLen={watchListLen}
                setWatchListLen={setWatchListLen}
              />
            ) : (
              <Redirect to="/" />
            )}
          </Route>
          <Route path="/watch-list">
            <WatchList
              watchList={watchList}
              SetWatchList={SetWatchList}
              watchListLen={watchListLen}
              setWatchListLen={setWatchListLen}
            />
          </Route>
          <Route exact path="/">
            <Row
              title="Trend Now"
              fetchUrl={requests.fetchTrending}
              isLarge={true}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              isFirst={true}
            />
            <Row
              title="Top Rated"
              fetchUrl={requests.fetchTopRated}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />

            <Row
              title="Netflix Originals"
              fetchUrl={requests.fetchNetflixOriginals}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="tv"
            />

            <Row
              title="Action"
              fetchUrl={requests.fetchActionMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Comedy"
              fetchUrl={requests.fetchComedyMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Animated"
              fetchUrl={requests.fetchAnimatedMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Family"
              fetchUrl={requests.fetchFamilyMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Drama"
              fetchUrl={requests.fetchDramaMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Fantasy"
              fetchUrl={requests.fetchFantasyMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="History"
              fetchUrl={requests.fetchHistoryMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Horror"
              fetchUrl={requests.fetchHorrorMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Romance"
              fetchUrl={requests.fetchRomanceMovies}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
            <Row
              title="Documentaries"
              fetchUrl={requests.fetchDocumentaries}
              setAllAboutMovie={setAllAboutMovie}
              setIsLoading={setIsLoading}
              mediaType="movie"
            />
          </Route>
        </Switch>
      </HashRouter>
    </div>
  );
}

export default App;
