import React from 'react'
import MovieCard from './MovieCard'
import done from '../images/done.svg'

function WatchList({watchList,SetWatchList,watchListLen,setWatchListLen}) {
    const doneHandler = (movie) => {
        const newList = watchList.filter((movieIn)=>movieIn.id!== movie.id)
        SetWatchList(newList)
        localStorage.setItem('watchlist',JSON.stringify(newList))
        setWatchListLen(watchListLen--)
    }
    return (
        <div className="watch_list">
            <div className="inner_watch_list">
                {watchList.map((movie)=>(
                    <div className="movie_card_in_watch_list_holder">
                        <MovieCard movie={movie} isLarge={false}/>
                        <span id="done" onClick={()=>doneHandler(movie)}><img src={done} alt="done"/></span>
                    </div>
                ))}
            </div>
        </div>
    )
}

export default WatchList
