import axios from "axios";
import React from "react";
import { useEffect, useState } from "react/cjs/react.development";
import useStatePromise from "use-state-promise";
import requests from "../requests";
import MovieCard from "./MovieCard";

function Collection({ movie }) {
  const collection_id = movie.belongs_to_collection.id;
  const [collection, setCollectionPromise, setCollection] = useStatePromise({});
  const [partss, setParts] = useState([]);
  useEffect(() => {
    const fetchCollections = async () => {
      const res = await axios.get(
        `https://api.themoviedb.org/3/collection/${collection_id}?api_key=${requests.apiKey}`
      );

      setCollectionPromise(() => {
        setCollection(res.data);
        return collection;
      }).then((collection) => setParts(collection.parts));
    };
    fetchCollections();
  }, [collection_id]);
  return (
    <div className="collectionHolder">
      <h1>{collection.name}</h1>
      <div className="row__posters">
        {partss.map((part, key) => (
          <div
            onClick={() => {
              window.scrollTo(0, 0);
            }}
            style={{ margin: "0 1em" }}
          >
            <MovieCard movie={part} key={key} mediaType="movie" />
          </div>
        ))}
      </div>
    </div>
  );
}

export default Collection;
