import React from 'react'
import Logo from './Logo'
import MenuBox from './MenuBox'

function NavBar({setMovieQuery,movies,setMovies,showSearchMenu, setShowSearchMenu,watchListLen}) {
    return (
        <nav id="NavBar">

            <div className="innerNavBar">
                <Logo/>
                <MenuBox setMovieQuery={setMovieQuery} movies={movies} setMovies={setMovies} showSearchMenu={showSearchMenu} setShowSearchMenu={setShowSearchMenu} watchListLen={watchListLen}/>
            </div>
            
        </nav>
    )
}

export default NavBar
