import React,{useState,useEffect} from 'react'
import axios from 'axios'
import requests from '../requests'
import Slider from "react-slick"
import { useMediaQuery } from 'react-responsive'
import WatchEpisode from './WatchEpisode'
function EpisodesHolder({currentSeason}) {
    
    const isBigScreen = useMediaQuery({ query: '(min-width: 787px)' })
    const settings = {
        dots: false,
        speed: 500,
        slidesToShow: 4,
        slidesToScroll: 4,
        initialSlide: 0,
        variableWidth: true,
        adaptiveHeight: true,
        infinite: false,
        focusOnSelect: true,
        arrows:true,
        
    };
    const [episodes,setEpisodes] = useState([])
    const [overview,setOverview] = useState("")
    const [currentEpisode,setCurrentEpisode] = useState(1)
    const [showWatchEpisode,setShowWatchEpisode] = useState(false)

    const [currentWatchNow,setCurrentWatchNow] = useState({id:currentSeason.id,season:currentSeason.season_number,episode:currentEpisode})

    useEffect(()=>{
        async function fetchIt() {
            const res = await axios.get(`https://api.themoviedb.org/3/tv/${currentSeason.id}/season/${currentSeason.season_number}?api_key=${requests.apiKey}`)
            setEpisodes(res.data.episodes)
            setOverview(res.data.overview)
        }
        fetchIt()
    },[currentSeason])

    const updateEpisode = (e)=>{
        setCurrentEpisode(e.target.dataset.episodenumber);
        setCurrentWatchNow({id:currentSeason.id,season:currentSeason.season_number,episode:e.target.dataset.episodenumber})
        setShowWatchEpisode(true)
        setTimeout(() => {
            window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' })
        }, 100);
    }
    return (
        <>
            <h1>{currentSeason.season_name}  <span>episodes</span></h1>
            {/* <p>{overview}</p> */}
            {isBigScreen ?(
                    
                <Slider {...settings} >
                    {episodes.map((episode,key)=>(
                        <div className="MovieCard episode_holder" id="episodeCard" >
                            <p>episode {episode.episode_number}</p>
                            <img src={requests.image_api+currentSeason.season_poster_path} id={key} alt={episode.episode_number} data-episodenumber={episode.episode_number} data-episodename={episode.name} onClick={updateEpisode}/>
                            
                            <h4 className="voteAvarage">{episode.vote_average > 0 ? episode.vote_average.toString().substring(0,3):"UV"} ⭐</h4>
                        </div>
                    ))}
                </Slider>):
                (<div className="row__posters">

                    {episodes.map((episode,key)=>(
                        <div className="MovieCard episode_holder" id="episodeCard" >
                            <p>episode {episode.episode_number}</p>
                            <img src={requests.image_api+currentSeason.season_poster_path} id={key} alt={episode.episode_number} data-episodenumber={episode.episode_number} data-episodename={episode.name} onClick={updateEpisode}/>
                            
                            <h4 className="voteAvarage">{episode.vote_average > 0 ? episode.vote_average.toString().substring(0,3):"UV"} ⭐</h4>
                        </div>
                    ))}

                </div>)
            }
            {showWatchEpisode?<WatchEpisode currentWatchNow={currentWatchNow}/>:""}
        </>
    )
}

export default EpisodesHolder
